import { sign, verify } from 'jsonwebtoken';
import { JwtPayload } from '../types';

// In a real application, these would be loaded from environment variables
// and should be strong, randomly generated secrets.
const ACCESS_TOKEN_SECRET = process.env.ACCESS_TOKEN_SECRET || 'supersecretaccesstokenkey';
const REFRESH_TOKEN_SECRET = process.env.REFRESH_TOKEN_SECRET || 'supersecretrefreshtokenkey';

// Expiration times (e.g., '15m', '7d')
const ACCESS_TOKEN_EXPIRATION = process.env.ACCESS_TOKEN_EXPIRATION || '15m';
const REFRESH_TOKEN_EXPIRATION = process.env.REFRESH_TOKEN_EXPIRATION || '7d';

export const generateAccessToken = (payload: JwtPayload): string => {
  return sign(payload, ACCESS_TOKEN_SECRET, { expiresIn: ACCESS_TOKEN_EXPIRATION });
};

export const generateRefreshToken = (payload: JwtPayload): string => {
  return sign(payload, REFRESH_TOKEN_SECRET, { expiresIn: REFRESH_TOKEN_EXPIRATION });
};

export const verifyAccessToken = (token: string): JwtPayload | null => {
  try {
    return verify(token, ACCESS_TOKEN_SECRET) as JwtPayload;
  } catch (error) {
    return null;
  }
};

export const verifyRefreshToken = (token: string): JwtPayload | null => {
  try {
    return verify(token, REFRESH_TOKEN_SECRET) as JwtPayload;
  } catch (error) {
    return null;
  }
};

export const getRefreshTokenExpirationTime = (): number => {
  // This is a simplified way to get the expiration time in milliseconds.
  // In a real app, you'd parse REFRESH_TOKEN_EXPIRATION string more robustly.
  const days = parseInt(REFRESH_TOKEN_EXPIRATION.replace('d', ''), 10);
  return Date.now() + (days * 24 * 60 * 60 * 1000);
};
