```aether:src/utils/refreshTokenStore.ts
import { RefreshTokenData } from '../types';
import { getRefreshTokenExpirationTime } from './jwt';

/**
 * A simple in-memory store for refresh tokens.
 * In a production environment, this would be replaced by a persistent store
 * like a database (e.g., Redis, PostgreSQL) to ensure durability and scalability.
 *
 * Key: The refresh token string itself.
 * Value: RefreshTokenData containing userId, creation/expiration timestamps, and validity status.
 */
const refreshTokenStore = new Map<string, RefreshTokenData>();

export const storeRefreshToken = (token: string, userId: string): void => {
  const now = Date.now();
  const expiresAt = getRefreshTokenExpirationTime(); // Get expiration based on JWT config
  refreshTokenStore.set(token, { userId, createdAt: now, expiresAt, isValid: true });
  console.log(`Stored refresh token for user ${userId}. Total tokens: ${refreshTokenStore.size}`);
};

export const getRefreshToken = (token: string): RefreshTokenData | undefined => {
  const tokenData = refreshTokenStore.get(token);
  if (tokenData && tokenData.expiresAt < Date.now()) {
    // Token has expired in our store, even if JWT verification might still pass for a short while.
    // Remove it and return undefined.
    refreshTokenStore.delete(token);
    return undefined;
  }
  return tokenData;
};

export const invalidateRefreshToken = (token: string): void => {
  const tokenData = refreshTokenStore.get(token);
  if (tokenData) {
    tokenData.isValid = false;
    // Optionally, remove it immediately or after a grace period
    refreshTokenStore.delete(token); // For simplicity, remove immediately
    console.log(`Invalidated and removed refresh token.`);
  }
};

/**
 * Cleans up expired tokens from the store.
 * In a real app, this would be a scheduled task.
 */
export const cleanupExpiredTokens = (): void => {
  const now = Date.now();
  let cleanedCount = 0;
  for (const [token, data] of refreshTokenStore.entries()) {
    if (data.expiresAt < now || !data.isValid) {
      refreshTokenStore.delete(token);
      cleanedCount++;
    }
  }
  if (cleanedCount > 0) {
    console.log(`Cleaned up ${cleanedCount} expired/invalidated refresh tokens.`);
  }
};

// Example: Run cleanup every hour (in a real app, this would be a background job)
setInterval(cleanupExpiredTokens, 60 * 60 * 1000);
