```aether:src/routes/auth.ts
import { Hono } from 'hono';
import { generateAccessToken, generateRefreshToken, verifyRefreshToken } from '../utils/jwt';
import { getRefreshToken, invalidateRefreshToken, storeRefreshToken } from '../utils/refreshTokenStore';

const authRoutes = new Hono();

authRoutes.post('/refresh', async (c) => {
  const { refreshToken } = await c.req.json();

  if (!refreshToken) {
    return c.json({ message: 'Refresh token is required' }, 400);
  }

  // 1. Verify the refresh token's signature and expiration
  const decodedRefreshToken = verifyRefreshToken(refreshToken);
  if (!decodedRefreshToken) {
    // If the token is invalid or expired, respond with 401
    return c.json({ message: 'Invalid or expired refresh token' }, 401);
  }

  // 2. Check if the refresh token exists and is valid in our store
  const storedTokenData = getRefreshToken(refreshToken);
  if (!storedTokenData || !storedTokenData.isValid || storedTokenData.userId !== decodedRefreshToken.userId) {
    // If the token is not found, invalidated, or doesn't match the decoded user,
    // it might indicate a stolen token or an attempt to use an invalidated token.
    // Invalidate all tokens for this user to prevent further use of potentially compromised tokens.
    // (This is a security measure, might be too aggressive for some apps)
    // For simplicity, we just return 401 here.
    return c.json({ message: 'Invalid or revoked refresh token' }, 401);
  }

  // 3. Invalidate the old refresh token (rotation)
  invalidateRefreshToken(refreshToken);

  // 4. Generate a new access token
  const newAccessToken = generateAccessToken({ userId: decodedRefreshToken.userId });

  // 5. Generate a new refresh token
  const newRefreshToken = generateRefreshToken({ userId: decodedRefreshToken.userId });

  // 6. Store the new refresh token
  storeRefreshToken(newRefreshToken, decodedRefreshToken.userId);

  return c.json({
    accessToken: newAccessToken,
    refreshToken: newRefreshToken,
  });
});

// Example login route for demonstration purposes (not part of the core feature request, but useful for testing)
authRoutes.post('/login', async (c) => {
  const { username, password } = await c.req.json();

  // In a real app, you'd verify username/password against a database
  if (username === 'user' && password === 'password') {
    const userId = 'user123'; // Example user ID

    const accessToken = generateAccessToken({ userId });
    const refreshToken = generateRefreshToken({ userId });

    storeRefreshToken(refreshToken, userId);

    return c.json({
      message: 'Login successful',
      accessToken,
      refreshToken,
    });
  } else {
    return c.json({ message: 'Invalid credentials' }, 401);
  }
});


export default authRoutes;
